 sec:{eyebrowKr:'四柱',eyebrow:'運命を読む四つの道',title:'占いを選んでください',lede:'東洋は生まれた時を読み、西洋はカードと星の流れを読みます。軽く見ても、深く読んでも大丈夫です。'},
 cards:{tj:{tag:'朝鮮王朝 · 新年運',title:'土亭秘訣',sub:'トジョンビギョル',desc:'韓国に伝わる一年の運勢。生年月日から卦を立て、今年の流れを読みます。',go:'今年を読む →'},saju:{tag:'四柱 · 八字',title:'四柱推命',sub:'サジュパルチャ',desc:'生まれた瞬間を天干と地支の四つの柱で読み解く、五行の設計図です。',go:'命式を立てる →'},tarot:{tag:'大アルカナ · 3枚スプレッド',title:'タロット',sub:'卜',desc:'過去、現在、未来。3枚を引いて、感じていたことに名前を与えます。',go:'カードを引く →'},zodiac:{tag:'西洋占星術 · 今日の運勢',title:'星座占い',sub:'星',desc:'今日の太陽星座の流れ。恋、仕事、幸運の数字まで確認できます。',go:'今日を見る →'}},
